/**
 * Level Data for Gravity Grid
 * 
 * Legend:
 * 0: Empty
 * 1: Platform Color A (Primary)
 * 2: Platform Color B (Secondary)
 * 3: Platform Color C (Accent)
 * 4: Spike Up
 * 5: Spike Down
 * 6: Crumbling Platform
 * 7: Gravity Switcher
 * 8: Coin (1000 pts)
 * 9: Small Coin (100 pts)
 */

const GRID_H = 18;

function createEmptyLevel(width = 100) {
    const level = [];
    for (let y = 0; y < GRID_H; y++) {
        const row = [];
        for (let x = 0; x < width; x++) {
            // Floor and Ceiling
            if (y === 0) {
                row.push(2);
            } else if (y === GRID_H - 1) {
                row.push(1);
            } else {
                row.push(0);
            }
        }
        level.push(row);
    }
    return level;
}

